import React, { useEffect, useRef } from 'react';
import { useParams } from 'react-router-dom';
import videojs from 'video.js';
import 'video.js/dist/video-js.css';

const Player = () => {
  const { id } = useParams();
  const videoRef = useRef(null);
  const playerRef = useRef(null);

  useEffect(() => {
    // Aquí cargarías la URL M3U8 de la película
    const videoSrc = 'https://fin-3dg-b1.r66nv9ed.com/hls2/02/10718/i9cg07s9uqnn_h/master.m3u8?t=FxHpMZnSAdZA5zgzxgwJUeAmd-VLF66qnJFCFhyog_U&s=1769897918&e=10800&f=53592037&srv=1065&asn=19114&sp=4000&p=0';

    if (videoRef.current && !playerRef.current) {
      playerRef.current = videojs(videoRef.current, {
        controls: true,
        responsive: true,
        fluid: true,
        sources: [{
          src: videoSrc,
          type: 'application/x-mpegURL'
        }]
      });
    }

    return () => {
      if (playerRef.current) {
        playerRef.current.dispose();
        playerRef.current = null;
      }
    };
  }, [id]);

  return (
    <div className="p-4">
      <video
        ref={videoRef}
        className="video-js vjs-default-skin w-full"
        controls
        preload="auto"
        data-setup="{}"
      />
    </div>
  );
};

export default Player;
